from fastapi import FastAPI, HTTPException
from pydantic import BaseModel
from datetime import datetime
import re
from app.validators.email_validator import validate_email
from app.validators.phone_validator import validate_phone

app = FastAPI()

class EmailRequest(BaseModel):
    email: str

class PhoneRequest(BaseModel):
    phone: str

class BatchItem(BaseModel):
    type: str
    value: str

class BatchRequest(BaseModel):
    items: list[BatchItem]

@app.post("/v1/validate/email")
def validate_email_endpoint(request: EmailRequest):
    sanitized_email = request.email.strip()[:256]
    if not validate_email(sanitized_email):
        raise HTTPException(status_code=400, detail="Invalid email address")
    return {
        "valid": True,
        "input": sanitized_email,
        "timestamp": datetime.utcnow().isoformat()
    }

@app.post("/v1/validate/phone")
def validate_phone_endpoint(request: PhoneRequest):
    sanitized_phone = request.phone.strip()[:256]
    if not validate_phone(sanitized_phone):
        raise HTTPException(status_code=400, detail="Invalid phone number")
    return {
        "valid": True,
        "input": sanitized_phone,
        "timestamp": datetime.utcnow().isoformat()
    }

@app.post("/v1/validate/batch")
def validate_batch_endpoint(request: BatchRequest):
    results = []
    for item in request.items[:100]:
        sanitized_value = item.value.strip()[:256]
        if item.type == "email":
            valid = validate_email(sanitized_value)
        elif item.type == "phone":
            valid = validate_phone(sanitized_value)
        else:
            valid = False
        results.append({
            "type": item.type,
            "value": sanitized_value,
            "valid": valid,
            "error": None if valid else "Invalid format"
        })
    return {
        "results": results,
        "processed_at": datetime.utcnow().isoformat()
    }

@app.get("/health/liveness")
def liveness():
    return {"status": "ok"}

@app.get("/health/readiness")
def readiness():
    return {"status": "ok"}

import re

def validate_phone(phone: str) -> bool:
    # Regex for E.164 aligned phone numbers
    phone_regex = re.compile(
        r"^\+?[1-9]\d{1,14}$",
        re.IGNORECASE
    )
    return bool(phone_regex.match(phone))
